<script setup lang="ts">const { open, loading, candidate, guidance, error, confirm, cancel } = usePreActionGuidance()</script>
<template><Teleport to="body"><div v-if="open" class="fixed inset-0 z-[140] grid place-items-center overflow-y-auto bg-gray-950/40 p-4" role="dialog" aria-modal="true" aria-label="Pre-action guidance" @mousedown.self="cancel"><section class="my-6 w-full max-w-3xl rounded-2xl bg-white shadow-2xl"><header class="flex items-start justify-between border-b p-5"><div><div class="text-[10px] font-semibold uppercase tracking-[.16em] text-blue-600">CADE · Portfolio digital twin</div><h2 class="mt-1 text-lg font-semibold">Before you {{ candidate?.intent?.toLowerCase() }}</h2><p class="mt-1 text-xs text-gray-500">Expected outcome, uncertainty, downside, and guardrails before anything changes.</p></div><button aria-label="Cancel action" @click="cancel">×</button></header><div class="max-h-[70vh] overflow-y-auto p-5"><div v-if="loading" class="rounded-xl border border-blue-200 bg-blue-50 p-6 text-sm text-blue-700">Running CADE signals and portfolio simulation…</div><div v-else-if="error" class="rounded-xl border border-red-200 bg-red-50 p-5 text-sm text-red-700">{{ error }}</div><template v-else-if="guidance"><div class="rounded-xl border p-4" :class="guidance.recommendation === 'proceed' ? 'border-emerald-200 bg-emerald-50' : guidance.recommendation === 'do_not_proceed' ? 'border-red-200 bg-red-50' : 'border-amber-200 bg-amber-50'"><div class="text-xs font-semibold uppercase">{{ guidance.recommendation.replaceAll('_', ' ') }}</div><div class="mt-1 text-sm font-medium">{{ guidance.summary }}</div></div><div class="mt-4 grid grid-cols-2 gap-3 sm:grid-cols-4"><div v-for="metric in [{l:'Expected value',v:guidance.expectedValue+'/100'},{l:'Success',v:Math.round(guidance.successProbability*100)+'%'},{l:'Risk',v:guidance.riskScore+'/100'},{l:'Confidence',v:Math.round(guidance.confidence*100)+'%'}]" :key="metric.l" class="rounded-xl border p-3"><div class="text-[10px] text-gray-400">{{ metric.l }}</div><div class="mt-1 text-lg font-semibold">{{ metric.v }}</div></div></div><div class="